    if !adl_was_triggered {
        adl_fill_ctx.last_update = clearinghouse.current_time;
        return result;
    }

    let mut remaining_shortfall: u64 = 0;
    let mut total_shortfall_value: u64 = 0;
    let mut asset_idx: u64 = 0;
    while asset_idx < clearinghouse.n_assets {
        if let Some(oracle_data) = clearinghouse.assets.get(&asset_idx) {
            let adl_value_unit = (oracle_data.bid as i128) - user_equity_unit;
            let shortfall_discriminant = (adl_candidates.shortfall_fn)(
                oracle_asset_data.px_index,
                oracle_asset_data.mark_price,
                oracle_asset_data.px_decimals,
            );
            let user_shortfall = shortfall_discriminant;
            let entry_user_shortfall = user_shortfall;
            total_shortfall_value = total_shortfall_value.saturating_add(entry_user_shortfall);
            if adl_value_unit < 0 && !deferred_only {
