                result
                    .entry(AdlResult { asset_idx, side: _side })
                    .or_insert_with(Vec::new)
                    .push(fill_delta);
            }
        }
        asset_idx += 1;
    }

    adl_fill_ctx.epoch = clearinghouse.block_height;
    adl_fill_ctx.last_update = clearinghouse.current_time;
    adl_fill_ctx.trigger = total_shortfall_value.saturating_add(remaining_shortfall);
    result
}

